AJAXAJAX란 비동기 자바스크립트와 XML (Asynchronous JavaScript And XML) 이다. 서버와 통신하기 위해 XMLHttpRequest 객체를 사용한다. JSON, XML, HTML 그리고 일반 텍스트 형식 등을 포함한 다양한 포맷을 주고 받을 수 있다. AJAX의 강력한 특징은 페이지 전체를 리프레쉬 하지 않고서도 수행 되는 “비동기성”이다. 이러한 비동기성을 통해 사용자의 Event가 있으면 전체 페이지가 아닌 일부분만 업데이트 할 수 있다.
XMLHttpRequestXHR 객체는 서버와 상호작용하기 위해 사용된다. 전체 페이지의 새로고침 없이도 URL로부터 데이터(모든 종류의)를 받아올 수 있다. 아래는 예제 코드이다.
var xhr = new XMLHttpRequest();xhr.open(&#x27;GET&#x27;, &#x27;/path/to/image.png&#x27;, true);// Hack to pass bytes through unprocessed.xhr.overrideMimeType(&#x27;text/plain; charset=x-user-defined&#x27;);xhr.onreadystatechange = function(e) &#123;  if (this.readyState == 4 &amp;&amp; this.status == 200) &#123;    var binStr = this.responseText;    for (var i = 0, len = binStr.length; i &lt; len; ++i) &#123;      var c = binStr.charCodeAt(i);      //String.fromCharCode(c &amp; 0xff);      var byte = c &amp; 0xff;  // byte at offset i    &#125;  &#125;&#125;;xhr.send();

responseTypeXMLHttpRequest는 어떠한 형식의 데이터도 전송이 가능하다고 하였다. 위의 예제를 통해 데이터를 받아 확인 할 수 있지만, 처리에 난감한 부분이 있다. 대신 XHR.responseType 지정을 통해 파일을 받고, mimeType을 설정해주는 방법을 사용할 수 있다. responseType은  “text”, “arraybuffer”, “blob”, or “document” 가 가능하고, 아무 설정을 해주지 않으면 “text”로 응답을 받는다.
var xhr = new XMLHttpRequest();xhr.open(&#x27;GET&#x27;, &#x27;/path/to/image.png&#x27;, true);xhr.responseType = &#x27;blob&#x27;;xhr.onload = function(e) &#123;  if (this.status == 200) &#123;    // Note: .response instead of .responseText    var blob = new Blob([this.response], &#123;type: &#x27;image/png&#x27;&#125;);    ...  &#125;&#125;;xhr.send();

blob &amp; arraybufferresponseType으로 file을 받을 때 blob과 arraybuffer 를 설정해 받을 수 있다. 이 둘은 file data를 받는 것은 동일하지만, arraybuffer는 javascript에서 조작하기 쉬운 array형태로 data를 받을수 있다는 차이점이 있다.  
axios responseType blob브라우저에서 XMLHttpRequest 객체를 이용해 통신 하는 모든 방법들은 위 설정을 활용하여 데이터를 주고 받을 수 있다. axios도 마찬가지다.
downFileGet()&#123;    axios(&#123;        method: &#x27;GET&#x27;,        url: &#x27;/GETDownload&#x27;,                         responseType: &#x27;blob&#x27;    &#125;)        .then(response =&gt;&#123;                const url = window.URL.createObjectURL(new Blob([response.data], &#123; type: response.headers[&#x27;content-type&#x27;] &#125;));        const link = document.createElement(&#x27;a&#x27;);        link.href = url;        link.setAttribute(&#x27;download&#x27;, &#x27;test.xlsx&#x27;);        document.body.appendChild(link);        link.click();    &#125;)                                &#125;downFilePost()&#123;  axios(&#123;      method: &#x27;POST&#x27;,      url: &#x27;/POSTdownload&#x27;,      responseType: &#x27;blob&#x27;,      headers: &#123;          &quot;Content-Type&quot;: &quot;application/json&quot;      &#125;,         data: &#123;          imgName: star             &#125;  &#125;)  .then(response =&gt;&#123;      const url = window.URL.createObjectURL(new Blob([response.data], &#123; type: response.headers[&#x27;content-type&#x27;] &#125;));      const link = document.createElement(&#x27;a&#x27;);      link.href = url;      link.setAttribute(&#x27;download&#x27;, &#x27;star.jpg&#x27;);      document.body.appendChild(link);      link.click();  &#125;)&#125;///// node server code //////const express = require(&quot;express&quot;);const fs = require(&quot;fs&quot;);const path = require(&quot;path&quot;);const mime = require(&quot;mime&quot;);const router = express.Router();router.use(express.json());router.post(&#x27;/&#x27;, function (req, res) &#123;    let file = &quot;./&quot; + req.body.filePath;    try &#123;      if (fs.existsSync(file)) &#123;        let fileName = req.body.fileName ? req.body.fileName : path.basename(file);        let mimetype = mime.getType(fileName);        res.setHeader(&quot;Content-Disposition&quot;, &quot;attachment; filename=&quot; + fileName);        res.setHeader(&quot;Content-Type&quot;,mimetype);        let fileStream = fs.createReadStream(file).on(&#x27;error&#x27;,(err)=&gt;&#123;console.log(&quot;CREATEWRITESTREAM ERROR !!&quot;,err)&#125;);        fileStream.pipe(res);      &#125; else &#123;        res.send(&quot;There is no such file.&quot;);        return;      &#125;    &#125; catch (e) &#123;      console.log(e);      res.send(&quot;There is an Error downloading your file.&quot;);      return;    &#125;&#125;);module.exports = router;


