react와 node.js를 이용해 간단한 웹 어플리케이션을 만들어보자. 이 글에서는 기본적인 어플리케이션 세팅을 다룬다.
Node.js 설치 확인터미널에 아래와 같이 명령어를 입력하여 Node.js가 설치되어있는지 확인한다.
node -vnpm -v
이 글은 node 10.21.0, npm 5.8.0 기준으로 작성하였다.
React 사용 준비npm 버전이 5.2 이상일 경우 아래 명령어를 통해 react를 사용할 수 있도록 준비한다.
npx install create-react-appcreate-react-app &#123;project name&#125;
이하 작업은 프로젝트 폴더 아래에서 진행한다. 프론트엔드에서 백엔드로 요청을 보낼때 사용하기 위해 axios를 설치한다.
npm install axios --save

백엔드 준비백엔드에서 사용할 미들웨어를 설치한다. 여기에서는 express를 사용한다. 몽고DB를 사용할 경우 mongodb도 함께 설치한다.
npm install express --savenpm install mongodb --save

프로젝트 폴더 아래에 server 폴더를 생성하고 그 아래에 server.js 파일을 만들어 백엔드 서버의 엔트리 포인트를 작성한다. mongodb 연결과 해제에 대한 내용과 서버 시작 로직을 ECMA5로 작성하였다.
//server.jsconst express = require(&#x27;express&#x27;);const app = express();const cors = require(&#x27;cors&#x27;);app.use(cors());const api = require(&#x27;./routes/index&#x27;);app.use(&#x27;/api&#x27;,api);const resultService = require(&#x27;./routes/resultService&#x27;);app.use(&#x27;/result&#x27;,resultService);var Client = require(&#x27;mongodb&#x27;).MongoClient;const url = &#x27;mogodb url&#x27;;Client.connect(url, function(error,db) &#123;    if (error) &#123;        console.log(&#x27;:::: connect error ::::&#x27;);        console.log(error);    &#125; else &#123;        console.log(&#x27;:::: connect success ::::&#x27;);        global.db = db;    &#125;&#125;)process.on(&#x27;SIGINT&#x27;, () =&gt; &#123;	  process.exit();&#125;);process.on(&#x27;exit&#x27;, () =&gt; &#123;    let db = global.db;    db.close((err) =&gt; &#123;        if (err) &#123;            console.log(&quot;server :: DB close ERROR &quot;,err);        &#125; else &#123;            console.log(&quot;server :: DB connection closed &quot;);        &#125;    &#125;);&#125;);const port = 30002;app.listen(port, ()=&gt;console.log(`Listening on port $&#123;port&#125;`));
server 폴더 아래 routes 폴더를 생성하고 실제 백엔드 로직 실행을 위한 파일들을 작성한다. 
