Observer Pattern
한 객체 상태 변화에 다라 다른 객체 상태도 연동되도록 일대다 객체 의존 관계를 구성하는 패턴
데이터 변경이 발생했을 결우 상대 클래스나 객체에 의존하지 않으면서 데이터 변경을 통보하고자 할 때 유용
옵저버 패턴은 통보 대상 객체의 관리르 Subject 클래스와 Observer 인터페이스로 일반화
데이터 변경을 통보하는 클래스(CondreteSubject)는 통보 대상 클래스나 객체에 대한 의존성을 없앨 수 있음

구현 예시야구 카운트 정보에 대한 정보를 보여주는 시스템이 있다고 가정하자. 야구 카운트에 대한 정보를 가진 Subject가 존재하고 이를 여러군데에서 보여주는 Observer 구현체들이 있다. 정보는 한군데에서 제공하고 Observer 구현체들은 여러 곳에서 여러 방식으로 정보를 보여줄 수 있다. Observer 구현체들은 여러가지 방법으로 구현 될 수 있고 이에 따라 정보를 보여주는 방법도 여러가지가 될 수 있다. Observer 구현체가 추가 되거나 다른 방식을 구현 되더라도 정보를 제공하는 Subject는 정보를 제공하기만 하기 때문에 이에 따른 변경이 필요 없다.
public interface Subject &#123;	public void registerObserver(Observer o);    public void removeObserver(Observer o);    public void notifyObservers();&#125;
public class BaseballStatus implements Subject &#123;	private ArrayList&lt;Observer&gt; observers;    private int strike;    private int ball;    private int out;    public BaseballStatus() &#123;        this.observers = new ArrayList&lt;&gt;();    &#125;    public int getStrike() &#123;    	return strike;    &#125;        public void setStrike(int strike) &#123;    	this.strike = strike;    &#125;    public int getBall() &#123;		return ball;	&#125;	public void setBall(int ball) &#123;		this.ball = ball;	&#125;	public int getOut() &#123;		return out;	&#125;	public void setOut(int out) &#123;		this.out = out;	&#125;	@Override    public void registerObserver(Observer o) &#123;        observers.add(o);    &#125;    @Override    public void removeObserver(Observer o) &#123;        int i = observers.indexOf(o);        if (i &gt;= 0) &#123;            observers.remove(i);        &#125;    &#125;    @Override    public void notifyObservers() &#123;        for (Observer o : observers) &#123;            o.update();        &#125;    &#125;    public void gameChanged() &#123;        notifyObservers();    &#125;    public void setGame(int strike, int ball, int out) &#123;        this.setStrike(strike);        this.ball = ball;        this.out = out;        gameChanged();    &#125;    &#125;
위는 야구 정보를 제공하는 Subject BaseballStatus에 대한 코드
public interface Observer &#123;	public void update();&#125;
public interface Display &#123;	public void display();&#125;
public class CurrentStateDisplayMonitor implements Observer, Display &#123;	private String monitorName;	private BaseballStatus baseballStatus;		public CurrentStateDisplayMonitor(String dn, BaseballStatus bs) &#123;		this.monitorName = dn;		this.baseballStatus = bs;		bs.registerObserver(this);	&#125;		@Override	public void display() &#123;		System.out.println(&quot;monitor: &quot; + monitorName);		System.out.println(&quot;Strike: &quot; + baseballStatus.getStrike() + &quot; Ball: &quot; + baseballStatus.getBall() + &quot; Out: &quot; + baseballStatus.getOut() );	&#125;	@Override	public void update() &#123;		display();	&#125;&#125;
위는 정보를 받아 보여주는 Observer 구현체이다. 이 구현체는 다른 방식을 구현된 클래스가 추가 될 수 있으나 정보를 제공하는 BaseballStatus인 Subject는 변경이 필요 없다.
public class ObserverMain &#123;		public static void main(String[] args) &#123;		BaseballStatus bs = new BaseballStatus();		CurrentStateDisplayMonitor monitor1 = new CurrentStateDisplayMonitor(&quot;시청역 전광판&quot;, bs);		CurrentStateDisplayMonitor monitor2 = new CurrentStateDisplayMonitor(&quot;광화문 전광판&quot;, bs);		CurrentStateDisplayMonitor monitor3 = new CurrentStateDisplayMonitor(&quot;테해란로 전광판&quot;, bs);				bs.setGame(0, 1, 0);		bs.setGame(1, 1, 0);		bs.setGame(1, 2, 0);		bs.setGame(1, 2, 1);	&#125;&#125;monitor: 시청역 전광판Strike: 0 Ball: 1 Out: 0monitor: 광화문 전광판Strike: 0 Ball: 1 Out: 0monitor: 테해란로 전광판Strike: 0 Ball: 1 Out: 0monitor: 시청역 전광판Strike: 1 Ball: 1 Out: 0monitor: 광화문 전광판Strike: 1 Ball: 1 Out: 0monitor: 테해란로 전광판Strike: 1 Ball: 1 Out: 0monitor: 시청역 전광판Strike: 1 Ball: 2 Out: 0monitor: 광화문 전광판Strike: 1 Ball: 2 Out: 0monitor: 테해란로 전광판Strike: 1 Ball: 2 Out: 0monitor: 시청역 전광판Strike: 1 Ball: 2 Out: 1monitor: 광화문 전광판Strike: 1 Ball: 2 Out: 1monitor: 테해란로 전광판Strike: 1 Ball: 2 Out: 1
BaseballStatus를 observer 구현체들에 등록하고 setGame을 통해 BaseballStatus가 변경될 때마다 정보가 표시되는 것을 확인 할 수 있다.
출처: https://gmlwjd9405.github.io/2018/07/08/observer-pattern.html  https://johngrib.github.io/wiki/observer-pattern/

opencv에서 재공하는 API를 이용해 영상의 관심영역을 생성하고, 밝기 보정 프로그램을 만들어 본다.

코드의 상세 내용을 설명하고 가장 마지막에 전체 코드를 공개한다.

비디오 캡쳐
이미지 저장은 Mat 클래스로 하지만, 영상을 불러올 때는 VideoCapture 클래스를 사용한다.

VideoCapture cap(&quot;./base_camera_dark.avi&quot;);


관심영역 생성을 위해 마스크를 만든다.
영상의 크기 정보를 얻어 w, h 변수에 저장한다.
마스크는 그레이 스케일로 만들고 0으로 초기화한다.(검은색)
벡터에 관심영역 정보를 담은 Point 클래스를 저장한다.
fillpoly 를 호출하여 마스크에 관심영역 부분을 흰색으로 채운다.

int w = cvRound(cap.get(CAP_PROP_FRAME_WIDTH));int h = cvRound(cap.get(CAP_PROP_FRAME_HEIGHT));Mat mask = Mat::zeros(h, w, CV_8UC1);vector&lt;Point&gt;  pts = &#123;  Point(240, 280),  Point(400, 280),  Point(620, 440),  Point(20, 440)&#125;;fillPoly(mask, &#123; pts &#125;, Scalar(255));


관심영역의 평균밝기를 구하고 보정하는 코드이다.
동영상에서 한 프레임을 가져와 Mat 클래스에 저장한다.
cvtColor 를 호출하여 컬러 영상을 그레이 스케일로 변환한다.
mean 을 호출하여 평균값을 구하는데 이전에 만들었던 마스크를 활용하여 관심영역 부분만 구한다.
구한 평균을 이용해 밝기를 보정한다.

cap &gt;&gt; frame;cvtColor(frame, gray, COLOR_BGR2GRAY);Scalar m = mean(gray, mask);dst = gray + (Scalar(128) - m);




아래는 동영상에 관심영역부분을 그려주는 내용이다.

line(frame, Point(240, 280), Point(400, 280), Scalar(255, 0, 0), 2);line(frame, Point(400, 280), Point(620, 440), Scalar(255, 0, 0), 2);line(frame, Point(620, 440), Point(20, 440), Scalar(255, 0, 0), 2);line(frame, Point(20, 440), Point(240, 280), Scalar(255, 0, 0), 2);



아래는 프래임 번호를 구해 화면에 그려주는 내용이다.

int pos = cvRound(cap.get(CAP_PROP_POS_FRAMES));String text = format(&quot;frame number: %d&quot;, pos);putText(frame, text, Point(20, 50), FONT_HERSHEY_SIMPLEX,  0.7, Scalar(0, 0, 255), 1, LINE_AA);




아래는 전체 코드.

#include &lt;iostream&gt;#include &quot;opencv2/opencv.hpp&quot;using namespace cv;using namespace std;int main()&#123;	VideoCapture cap(&quot;./base_camera_dark.avi&quot;);	if (!cap.isOpened()) &#123;		cerr &lt;&lt; &quot;Video open failed!&quot; &lt;&lt; endl;		return -1;	&#125;	int w = cvRound(cap.get(CAP_PROP_FRAME_WIDTH));	int h = cvRound(cap.get(CAP_PROP_FRAME_HEIGHT));	Mat mask = Mat::zeros(h, w, CV_8UC1);	vector&lt;Point&gt;  pts = &#123;		Point(240, 280),		Point(400, 280),		Point(620, 440),		Point(20, 440)	&#125;;	fillPoly(mask, &#123; pts &#125;, Scalar(255));	Mat frame;	Mat gray;	Mat dst;	while (true) &#123;		cap &gt;&gt; frame;		if (frame.empty()) &#123;			cerr &lt;&lt; &quot;Empty frame!&quot; &lt;&lt; endl;			break;		&#125;		cvtColor(frame, gray, COLOR_BGR2GRAY);		imshow(&quot;gray&quot;, gray);		Scalar m = mean(gray, mask);		dst = gray + (Scalar(128) - m);		imshow(&quot;dst&quot;, dst);		line(frame, Point(240, 280), Point(400, 280), Scalar(255, 0, 0), 2);		line(frame, Point(400, 280), Point(620, 440), Scalar(255, 0, 0), 2);		line(frame, Point(620, 440), Point(20, 440), Scalar(255, 0, 0), 2);		line(frame, Point(20, 440), Point(240, 280), Scalar(255, 0, 0), 2);		int pos = cvRound(cap.get(CAP_PROP_POS_FRAMES));		String text = format(&quot;frame number: %d&quot;, pos);		putText(frame, text, Point(20, 50), FONT_HERSHEY_SIMPLEX,			0.7, Scalar(0, 0, 255), 1, LINE_AA);		imshow(&quot;frame&quot;, frame);		if (waitKey(10) == 27)			break;	&#125;	cap.release();	destroyAllWindows();&#125;
